export function readAgentsMeta(projectRoot: string): AgentsMeta {
  const metaPath = getAgentsMetaPath(projectRoot);
  let raw: string;
  try {
    raw = readFileSync(metaPath, 'utf8');
  } catch (error) {
    if (error && typeof error === 'object' && 'code' in error && error.code === 'ENOENT') {
      throw new AgentsMetaFileMissingError(metaPath);
    }
    throw error;
  }
  try {
    return agentsMetaSchema.parse(JSON.parse(raw));
  } catch (error) {
    throw new AgentsMetaInvalidError(metaPath, error);
  }
}

export async function loadGetRulesContext(projectRoot: string): Promise<GetRulesContext> {
  const meta = readAgentsMeta(projectRoot); // SYNC
  const l0Content = await readFile(join(projectRoot, 'AGENTS.md'), 'utf8');
  const humanLockedNearby = (await readHumanLock(projectRoot)).map((entry) => ({
    file: entry.file,
    excerpt: JSON.stringify(entry),
  }));
  return { meta, l0Content, humanLockedNearby };
}

async function loadRulesForPath(
  projectRoot: string,
  meta: AgentsMeta,
  path: string,
): Promise<LoadedRule[]> {
  const requestedPath = normalizeRulesPath(path);
  const matchedNodes = Object.entries(meta.nodes)
    .filter(([, node]) => minimatch(requestedPath, normalizeRulesPath(node.scope_glob), { dot: true }))
    .sort((left, right) => { ... });
  return await Promise.all(
    matchedNodes.map(async ([nodeId, node]) => ({
      level: classifyNode(nodeId),
      entry: {
        path: node.file,
        content: await readFile(join(projectRoot, node.file), 'utf8'),
      },
    }))
  );
}

export async function appendEditIntentAuditEvents(
  projectRoot: string,
  input: { affected_paths: string[]; intent: string; ledger_entry_id: string; ts?: number; window_ms?: number; }
): Promise<EditIntentAuditEntry[]> {
  const ts = input.ts ?? Date.now();
  const windowMs = input.window_ms ?? DEFAULT_AUDIT_WINDOW_MS; // 5 * 60 * 1000
  const getRulesEntries = (await readAuditLog(projectRoot)).filter(isGetRulesAuditEntry);
  const entries = input.affected_paths.map((affectedPath) => {
    const path = normalizeAuditPath(projectRoot, affectedPath);
    const matchedGetRules = findPrecedingGetRulesEvent(getRulesEntries, path, ts, windowMs);
    return { ..., compliant: matchedGetRules !== null, ... };
  });
  if (entries.length === 0) return [];
  await appendAuditLogEntries(projectRoot, entries);
  return entries;
}

class JsonlEventStore implements EventStore {
  constructor(private readonly ledgerPath: string) {}
  async storeEvent(streamId, message): Promise<EventId> {
    const eventId = randomUUID();
    const entry = { kind: 'mcp-event', eventId, streamId, message };
    await appendFile(this.ledgerPath, `${JSON.stringify(entry)}\n`, 'utf8');
    return eventId;
  }
  async replayEventsAfter(lastEventId, { send }): Promise<StreamId> {
    const events = await this.readEvents(); // reads ENTIRE file
    const startIndex = events.findIndex((event) => event.eventId === lastEventId); // O(N)
    if (startIndex === -1) throw new Error(`Unknown event ID: ${lastEventId}`);
    const streamId = events[startIndex]?.streamId;
    for (const event of events.slice(startIndex + 1)) {
      if (event.streamId !== streamId) continue;
      await send(event.eventId, event.message);
    }
    return streamId;
  }
  private async readEvents(): Promise<StoredMcpEvent[]> { /* readFile entire file */ }
}

async function createSession(eventStore, sessions): Promise<FabricHttpSession> {
  const { createFabricServer } = await import('./index.js');
  const server = createFabricServer();
  const transport = new StreamableHTTPServerTransport({
    sessionIdGenerator: randomUUID,
    enableJsonResponse: true,
    eventStore,
    onsessioninitialized: async (sessionId) => {
      sessions.set(sessionId, { server, transport });
    },
    onsessionclosed: async (sessionId) => {
      sessions.delete(sessionId);
    },
  });
  transport.onclose = () => { const sessionId = transport.sessionId; if (sessionId) sessions.delete(sessionId); };
  await server.connect(transport);
  return { server, transport };
}

async function readLedgerAppendedEvents(state, projectRoot): Promise<FabricEvent[]> {
  const ledgerPath = join(projectRoot, LEDGER_PATH);
  const nextSize = await readFileSize(ledgerPath);
  if (nextSize < state.ledgerOffset) { state.ledgerOffset = 0; state.ledgerRemainder = ''; }
  if (nextSize === state.ledgerOffset) return [];
  const startOffset = state.ledgerOffset;
  state.ledgerOffset = nextSize;
  const handle = await open(ledgerPath, 'r');
  try {
    const length = nextSize - startOffset;
    const buffer = Buffer.alloc(length);
    await handle.read(buffer, 0, length, startOffset);
    const chunk = `${state.ledgerRemainder}${buffer.toString('utf8')}`;
    const lines = chunk.split(/\r?\n/);
    state.ledgerRemainder = chunk.endsWith('\n') ? '' : lines.pop() ?? '';
    return lines.map(...).filter(...);
  } finally { await handle.close(); }
}

